import { Utils } from './Utils'

/**
 * Transform JS regex string to RE2 regex string
 */
class TranslateRegExpString {
  static isUpperCaseAlpha(ch) {
    return 'A' <= ch && ch <= 'Z'
  }

  static isHexadecimal(ch) {
    return ('0' <= ch && ch <= '9') || ('A' <= ch && ch <= 'F') || ('a' <= ch && ch <= 'f')
  }

  static translate(data) {
    if (typeof data !== 'string') {
      return data
    }

    let result = ''
    let changed = false
    let size = data.length

    if (size === 0) {
      result = '(?:)'
      changed = true
    }

    let i = 0
    while (i < size) {
      let ch = data[i]

      if (ch === '\\') {
        if (i + 1 < size) {
          ch = data[i + 1]
          switch (ch) {
            case '\\': {
              result += '\\\\'
              i += 2
              continue
            }
            case 'c': {
              if (i + 2 < size) {
                let nextCh = data[i + 2]
                let code = nextCh.charCodeAt(0)
                if ((code >= 65 && code <= 90) || (code >= 97 && code <= 122)) {
                  let val = code % 32
                  result += '\\x'
                  result += (val >> 4).toString(16).toUpperCase()
                  result += (val & 15).toString(16).toUpperCase()
                  i += 3
                  changed = true
                  continue
                }
              }
              result += 'c'
              i += 2
              changed = true
              continue
            }
            case 'u': {
              if (i + 2 < size) {
                let nextCh = data[i + 2]
                if (nextCh === '{') {
                  result += '\\x'
                  i += 2
                  changed = true
                  continue
                } else if (i + 5 < size) {
                  let isHex4 = true
                  for (let j = 0; j < 4; j++) {
                    if (!TranslateRegExpString.isHexadecimal(data[i + 2 + j])) {
                      isHex4 = false
                      break
                    }
                  }
                  if (isHex4) {
                    result += '\\x{' + data.substring(i + 2, i + 6) + '}'
                    i += 6
                    changed = true
                    continue
                  }
                }
              }
              result += 'u'
              i += 2
              changed = true
              continue
            }
            default: {
              result += '\\'
              let cp = data.codePointAt(i + 1)
              let symSize = Utils.charCount(cp)
              result += data.substring(i + 1, i + 1 + symSize)
              i += symSize + 1
              continue
            }
          }
        }
      } else if (ch === '/') {
        result += '\\/'
        i += 1
        changed = true
        continue
      } else if (ch === '(' && i + 2 < size && data[i + 1] === '?' && data[i + 2] === '<') {
        if (i + 3 < size && !'=!>)'.includes(data[i + 3])) {
          result += '(?P<'
          i += 3
          changed = true
          continue
        }
      }

      let cp = data.codePointAt(i)
      let symSize = Utils.charCount(cp)
      result += data.substring(i, i + symSize)
      i += symSize
    }

    return changed ? result : data
  }
}

export { TranslateRegExpString }
